// Extract optional base font size and viewport width from input
const baseMatch = input.match(/base[:\s]+([\d.]+)\s*px/i);
const vpMatch = input.match(/viewport[:\s]+([\d.]+)\s*px/i);
const BASE_FONT = baseMatch ? parseFloat(baseMatch[1]) : 16;
const VIEWPORT  = vpMatch  ? parseFloat(vpMatch[1])  : 1440;

const re = /(-?[\d.]+)\s*(px|rem|em|pt|vw)\b/gi;
const lines = [
  `Base font size: ${BASE_FONT}px`,
  `Viewport width: ${VIEWPORT}px`,
  '',
];
let m;
while ((m = re.exec(input)) !== null) {
  const val  = parseFloat(m[1]);
  const unit = m[2].toLowerCase();
  let px;
  if      (unit === 'px')  px = val;
  else if (unit === 'rem') px = val * BASE_FONT;
  else if (unit === 'em')  px = val * BASE_FONT;
  else if (unit === 'pt')  px = val * 1.3333;
  else if (unit === 'vw')  px = val * VIEWPORT / 100;
  const rem = px / BASE_FONT;
  const pt  = px / 1.3333;
  const vw  = px / VIEWPORT * 100;
  lines.push(`${val}${unit}`);
  lines.push(`  px:   ${px.toFixed(3)}`);
  lines.push(`  rem:  ${rem.toFixed(4)}`);
  lines.push(`  em:   ${rem.toFixed(4)}`);
  lines.push(`  pt:   ${pt.toFixed(3)}`);
  lines.push(`  vw:   ${vw.toFixed(4)}%`);
  lines.push('');
}
if (lines.length <= 3) return { output: '', error: 'No CSS values found. Try "16px" or "1rem".' };
return { output: lines.join('\n').trimEnd(), outputLanguage: 'text' };
